command('deploy')
	.flag('token', flag.string().env('AUTH_TOKEN'))
	.derive(({ flags }) => {
		if (!flags.token)
			throw new CLIError('Not authenticated', {
				code: 'AUTH_REQUIRED',
				suggest: 'Run `mycli login`',
			});
		return { token: flags.token };
	})
	.action(({ ctx }) => {
		ctx.token; // string — typed
	});
